"use client";

import { useEffect, useMemo, useState } from "react";
import type { DailyGame } from "@/api/getGame";
import { normalizeAnswer } from "@/api/getGame";
import GuessInput from "@/components/GuessInput";
import ImageReveal from "@/components/ImageReveal";

type StoredState = {
  puzzleKey: string;
  guesses: string[];
  status: "playing" | "won" | "lost";
};

function storageKey(puzzleKey: string) {
  return `gtg:v1:${puzzleKey}`;
}

function isCorrectGuess(game: DailyGame, rawGuess: string) {
  const g = normalizeAnswer(rawGuess);
  if (!g) return false;
  const ok = new Set<string>([
    normalizeAnswer(game.title),
    ...(game.acceptableAnswers ?? []).map(normalizeAnswer),
  ]);
  return ok.has(g);
}

export default function GameBoard({ game }: { game: DailyGame }) {
  const [guesses, setGuesses] = useState<string[]>([]);
  const [status, setStatus] = useState<StoredState["status"]>("playing");
  const [message, setMessage] = useState<string>("");

  const maxGuesses = game.maxGuesses ?? 6;
  const remaining = Math.max(0, maxGuesses - guesses.length);
  const unlockedCount = Math.min(game.images.length || 6, Math.max(1, guesses.length + 1));

  const finished = status !== "playing";

  const helperText = useMemo(() => {
    if (status === "won") return `你猜对了！答案是「${game.title}」。`;
    if (status === "lost") return `次数用完了。答案是「${game.title}」。`;
    return `剩余次数：${remaining} / ${maxGuesses}`;
  }, [game.title, maxGuesses, remaining, status]);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(storageKey(game.puzzleKey));
      if (!raw) return;
      const parsed = JSON.parse(raw) as StoredState;
      if (parsed?.puzzleKey !== game.puzzleKey) return;
      setGuesses(Array.isArray(parsed.guesses) ? parsed.guesses : []);
      setStatus(parsed.status ?? "playing");
    } catch {
      // ignore
    }
  }, [game.puzzleKey]);

  useEffect(() => {
    const st: StoredState = { puzzleKey: game.puzzleKey, guesses, status };
    try {
      localStorage.setItem(storageKey(game.puzzleKey), JSON.stringify(st));
    } catch {
      // ignore
    }
  }, [game.puzzleKey, guesses, status]);

  function submitGuess(rawGuess: string) {
    if (finished) return;

    const cleaned = rawGuess.trim();
    if (!cleaned) return;

    const nextGuesses = [...guesses, cleaned].slice(0, maxGuesses);
    setGuesses(nextGuesses);

    if (isCorrectGuess(game, cleaned)) {
      setStatus("won");
      setMessage("正确！");
      return;
    }

    const used = nextGuesses.length;
    if (used >= maxGuesses) {
      setStatus("lost");
      setMessage("很可惜，没猜中。");
      return;
    }

    setMessage(`不对，再试试（已解锁线索 ${Math.min(unlockedCount + 1, 6)}/6）`);
  }

  return (
    <main className="grid gap-4">
      <section className="rounded-2xl border border-line bg-card p-4 shadow-soft">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div>
            <div className="text-sm text-muted">今日题目</div>
            <div className="text-lg font-semibold tracking-tight">猜游戏</div>
          </div>
          <div className="flex items-center gap-2">
            <div className="rounded-xl border border-line bg-white px-3 py-2 text-sm">
              尝试：<span className="font-semibold">{guesses.length}</span>/{maxGuesses}
            </div>
            <div className="rounded-xl border border-line bg-white px-3 py-2 text-sm">
              线索：<span className="font-semibold">{unlockedCount}</span>/6
            </div>
          </div>
        </div>

        {message ? (
          <div
            className={[
              "mt-3 rounded-xl border px-3 py-2 text-sm",
              status === "won"
                ? "border-green-200 bg-green-50 text-green-800"
                : status === "lost"
                  ? "border-red-200 bg-red-50 text-red-800"
                  : "border-slate-200 bg-slate-50 text-slate-700",
            ].join(" ")}
          >
            {message}
          </div>
        ) : null}

        <div className="mt-4">
          <div className="text-sm font-medium">历史猜测</div>
          {guesses.length ? (
            <div className="mt-2 flex flex-wrap gap-2">
              {guesses.map((g, i) => {
                const ok = isCorrectGuess(game, g);
                return (
                  <span
                    key={`${i}-${g}`}
                    className={[
                      "rounded-full border px-3 py-1 text-xs font-medium",
                      ok ? "border-green-200 bg-green-50 text-green-800" : "border-line bg-white text-slate-700",
                    ].join(" ")}
                  >
                    {g}
                  </span>
                );
              })}
            </div>
          ) : (
            <div className="mt-2 text-xs text-muted">还没有提交过猜测。</div>
          )}
        </div>
      </section>

      <ImageReveal images={game.images} unlockedCount={unlockedCount} />

      <GuessInput disabled={finished} onSubmitGuess={submitGuess} helperText={helperText} />

      <section className="rounded-2xl border border-line bg-card p-4 shadow-soft">
        <div className="text-sm font-medium">配置说明（你后续要改的地方）</div>
        <ul className="mt-2 list-disc pl-5 text-xs text-muted">
          <li>
            在 <code className="rounded bg-slate-100 px-1">public/images/</code> 放 6 张图片（从难到易或从糊到清）。
          </li>
          <li>
            在 <code className="rounded bg-slate-100 px-1">data/games.json</code> 的对应条目里把{" "}
            <code className="rounded bg-slate-100 px-1">images</code> 改成这些路径。
          </li>
          <li>每天会按日期（UTC）轮换一题：题库越多越好玩。</li>
        </ul>
      </section>
    </main>
  );
}

